sql:
SELECT SUM(settlement_amount) AS total_settled_amount
FROM claims
WHERE status = 'settled';

SELECT COUNT(*) AS total_claims
FROM claims
WHERE status = 'open';

external_knowledge:
- "master craftsmen" metaphorically refers to skilled attorneys;
- "crafted claims" refers to the injury claims filed by their clients;
- "calendar year of 2023" is the time period between '2023-01-01' and '2023-12-31'.

sql:
SELECT claimant_id, first_name
FROM claimants
WHERE last_name = 'Smith';

SELECT claim_id, value_of_injury_claim
FROM claims
ORDER BY value_of_injury_claim DESC;

SELECT claimant_id, SUM(value_of_injury_claim) AS total_value_of_claims
FROM claims
GROUP BY claimant_id;

SELECT AVG(value_of_injury_claim) AS average_injury_claim_value
FROM claims
WHERE status = 'settled';

SELECT AVG(value_of_injury_claim) AS average_injury_claim_value
FROM claims
WHERE date_of_filing BETWEEN '2023-01-01' AND '2023-12-31';

external_knowledge:
- "golden apples" metaphorically refer to the top claims in terms of value; 
- "orchard of settled claims" symbolizes the pool of settled claims; 
- "last two years" refers to claims filed between January 1, 2022, and December 31, 2023; 
- "identities" refer to the claimant ID and claim ID; 
- "the details of the incidents" refer to the case number, date of incident, and injury description; 
- "cost of healing" refers to the total medical expenses; 
- "value of lost time" refers to the total income lost; 
- "document maturity" refers to the average document version.

sql:
SELECT claim_id, amount
FROM medical_expenses
WHERE payment_status = 'paid';

SELECT claim_id, SUM(total_medical_expenses) AS cumulative_financial_burden
FROM claims
GROUP BY claim_id;

SELECT first_name, last_name
FROM claimants
WHERE claimant_id = 1;

external_knowledge:
- "guiding lights" metaphorically refers to the claimants leading their cases; 
- "tempests" metaphorically represents the tumultuous claims they are dealing with;
- "total storm of medical bills" metaphorically represents the sum total of medical expenses they have incurred;
- "economic whirlwind" metaphorically represents the financial turmoil caused by lost income due to injuries.

sql:
SELECT claim_id, total_medical_expenses
FROM claims
ORDER BY total_medical_expenses DESC;

external_knowledge:
- 'highly involved in injury litigation' refers to 'Alice Johnson', an attorney known for handling numerous injury claims. ;
- The total value of injury claims refers to the sum of all calculated values for injury claims managed by the specified attorney. ;
- The average claim value is the mean of the calculated values of the injury claims managed by the attorney. ;
- The total settlement amount is the sum of all final settlement amounts for the claims.

sql:
SELECT SUM(value_of_injury_claim) AS total_settlement_amount
FROM claims
WHERE status = 'settled' AND settlement_amount > 50000;
